        sa_start = time.time()
        sa_budget = remaining_time * 0.95

        iterations = 0
        improvements = 0
        stagnation = 0
        last_improvement_time = sa_start

        while True:
            now = time.time()
            sa_elapsed = now - sa_start
            if sa_elapsed >= sa_budget:
                break

            progress = sa_elapsed / sa_budget
            T = T_start * ((T_end / T_start) ** progress)

            # Choose move type
            r = random.random()
            if r < 0.45:
                # Swap move
                i = random.randint(0, n - 2)
                j = random.randint(i + 1, n - 1)
                # Apply swap
                current[i], current[j] = current[j], current[i]
                # Evaluate from position i onwards
                new_cost = suffix_eval(current, i, prefix_states[i][0], prefix_states[i][1])
                delta = new_cost - current_cost

                if delta < 0 or (T > 0 and random.random() < math.exp(-delta / T)):
                    current_cost = new_cost
                    # Recompute prefix states from position i
                    # Only recompute affected portion
                    key_state = dict(prefix_states[i][0])
                    total_cost = prefix_states[i][1]
                    for idx in range(i, n):
                        txn_idx = current[idx]
                        ops = txns_data[txn_idx]
                        txn_start = 1
                        txn_len = ops[0][3]
                        for (is_write, key, pos, _) in ops:
                            if key in key_state:
                                latest_end, latest_is_write, last_write_time = key_state[key]
                                if latest_is_write or is_write:
                                    conflict_time = latest_end + 1
                                else:
                                    conflict_time = last_write_time + 1 if last_write_time >= 0 else 0
                                constraint = conflict_time - pos + 1
                                if constraint > txn_start:
                                    txn_start = constraint
                        txn_end = txn_start + txn_len - 1
                        cost_inc = txn_end - total_cost
                        if cost_inc < 0:
                            cost_inc = 0
                        total_cost += cost_inc
                        for (is_write, key, pos, _) in ops:
                            actual_time = txn_start + pos - 1
                            if key in key_state:
                                latest_end2, latest_is_write2, last_write_time2 = key_state[key]
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    new_latest = actual_time if actual_time > latest_end2 else latest_end2
                                    key_state[key] = (new_latest, False, last_write_time2)
                            else:
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    key_state[key] = (actual_time, False, -1)
                        prefix_states[idx + 1] = (dict(key_state), total_cost)

                    if current_cost < best_cost:
                        best_cost = current_cost
                        best_schedule = list(current)
                        last_improvement_time = now
                        improvements += 1
                    stagnation = 0
                else:
                    # Revert swap
                    current[i], current[j] = current[j], current[i]
                    stagnation += 1

            elif r < 0.80:
                # Insertion move
                i = random.randint(0, n - 1)
                j = random.randint(0, n - 1)
                if i == j:
                    continue
                txn = current[i]
                current.pop(i)
                if j > i:
                    j -= 1
                current.insert(j, txn)
                start_pos = min(i, j)
                new_cost = suffix_eval(current, start_pos, prefix_states[start_pos][0], prefix_states[start_pos][1])
                delta = new_cost - current_cost

                if delta < 0 or (T > 0 and random.random() < math.exp(-delta / T)):
                    current_cost = new_cost
                    # Recompute prefix states from start_pos
                    key_state = dict(prefix_states[start_pos][0])
                    total_cost = prefix_states[start_pos][1]
                    for idx in range(start_pos, n):
                        txn_idx = current[idx]
                        ops = txns_data[txn_idx]
                        txn_start = 1
                        txn_len = ops[0][3]
                        for (is_write, key, pos, _) in ops:
                            if key in key_state:
                                latest_end, latest_is_write, last_write_time = key_state[key]
                                if latest_is_write or is_write:
                                    conflict_time = latest_end + 1
                                else:
                                    conflict_time = last_write_time + 1 if last_write_time >= 0 else 0
                                constraint = conflict_time - pos + 1
                                if constraint > txn_start:
                                    txn_start = constraint
                        txn_end = txn_start + txn_len - 1
                        cost_inc = txn_end - total_cost
                        if cost_inc < 0:
                            cost_inc = 0
                        total_cost += cost_inc
                        for (is_write, key, pos, _) in ops:
                            actual_time = txn_start + pos - 1
                            if key in key_state:
                                latest_end2, latest_is_write2, last_write_time2 = key_state[key]
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    new_latest = actual_time if actual_time > latest_end2 else latest_end2
                                    key_state[key] = (new_latest, False, last_write_time2)
                            else:
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    key_state[key] = (actual_time, False, -1)
                        prefix_states[idx + 1] = (dict(key_state), total_cost)

                    if current_cost < best_cost:
                        best_cost = current_cost
                        best_schedule = list(current)
                        last_improvement_time = now
                        improvements += 1
                    stagnation = 0
                else:
                    # Revert insertion
                    current.pop(j)
                    if j < i:
                        i_orig = i
                    else:
                        i_orig = i
                    current.insert(i, txn)
                    stagnation += 1

            else:
                # Or-opt: move a segment of length 2-4
                seg_len = random.randint(2, 4)
                if seg_len >= n:
                    continue
                i = random.randint(0, n - seg_len)
                segment = current[i:i + seg_len]
                del current[i:i + seg_len]
                j = random.randint(0, n - seg_len)
                current[j:j] = segment
                start_pos = min(i, j)
                new_cost = suffix_eval(current, start_pos, prefix_states[start_pos][0], prefix_states[start_pos][1])
                delta = new_cost - current_cost

                if delta < 0 or (T > 0 and random.random() < math.exp(-delta / T)):
                    current_cost = new_cost
                    # Recompute prefix states from start_pos
                    key_state = dict(prefix_states[start_pos][0])
                    total_cost = prefix_states[start_pos][1]
                    for idx in range(start_pos, n):
                        txn_idx = current[idx]
                        ops = txns_data[txn_idx]
                        txn_start = 1
                        txn_len = ops[0][3]
                        for (is_write, key, pos, _) in ops:
                            if key in key_state:
                                latest_end, latest_is_write, last_write_time = key_state[key]
                                if latest_is_write or is_write:
                                    conflict_time = latest_end + 1
                                else:
                                    conflict_time = last_write_time + 1 if last_write_time >= 0 else 0
                                constraint = conflict_time - pos + 1
                                if constraint > txn_start:
                                    txn_start = constraint
                        txn_end = txn_start + txn_len - 1
                        cost_inc = txn_end - total_cost
                        if cost_inc < 0:
                            cost_inc = 0
                        total_cost += cost_inc
                        for (is_write, key, pos, _) in ops:
                            actual_time = txn_start + pos - 1
                            if key in key_state:
                                latest_end2, latest_is_write2, last_write_time2 = key_state[key]
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    new_latest = actual_time if actual_time > latest_end2 else latest_end2
                                    key_state[key] = (new_latest, False, last_write_time2)
                            else:
                                if is_write:
                                    key_state[key] = (actual_time, True, actual_time)
                                else:
                                    key_state[key] = (actual_time, False, -1)
                        prefix_states[idx + 1] = (dict(key_state), total_cost)

                    if current_cost < best_cost:
                        best_cost = current_cost
                        best_schedule = list(current)
                        last_improvement_time = now
                        improvements += 1
                    stagnation = 0
                else:
                    # Revert or-opt
                    del current[j:j + seg_len]
                    current[i:i] = segment
                    stagnation += 1

            iterations += 1

            # Restart from best if stagnant
            if stagnation > 5000 and current_cost > best_cost:
                current = list(best_schedule)
                current_cost = best_cost
                _, prefix_states = fast_eval_with_states(current)
                stagnation = 0

    # Verify with official evaluator
    final_cost = workload.get_opt_seq_cost(best_schedule)
    return final_cost, best_schedule

# EVOLVE-BLOCK-END

def get_random_costs():
    workload_size = 100
    workload = Workload(WORKLOAD_1)

    makespan1, schedule1 = get_best_schedule(workload, 10)
    cost1 = workload.get_opt_seq_cost(schedule1)

    workload2 = Workload(WORKLOAD_2)
    makespan2, schedule2 = get_best_schedule(workload2, 10)
    cost2 = workload2.get_opt_seq_cost(schedule2)

    workload3 = Workload(WORKLOAD_3)
    makespan3, schedule3 = get_best_schedule(workload3, 10)
    cost3 = workload3.get_opt_seq_cost(schedule3)
    print(cost1, cost2, cost3)
    return cost1 + cost2 + cost3, [schedule1, schedule2, schedule3]


